SELECT [DDT_Picking Line].[Document No_], [DDT_Picking Line].Type, Sum(Val([quantity])) AS qty, [DDT_Picking Line].No_
FROM [DDT_Picking Line]
GROUP BY [DDT_Picking Line].[Document No_], [DDT_Picking Line].Type, [DDT_Picking Line].No_
HAVING ((([DDT_Picking Line].[Document No_])="SPD-25/06501" Or ([DDT_Picking Line].[Document No_])="SPD-25/06502" Or ([DDT_Picking Line].[Document No_])="SPD-25/06507" Or ([DDT_Picking Line].[Document No_])="SPD-25/06550" Or ([DDT_Picking Line].[Document No_])="SPD-25/06552" Or ([DDT_Picking Line].[Document No_])="SPD-25/06560" Or ([DDT_Picking Line].[Document No_])="SPD-25/06568" Or ([DDT_Picking Line].[Document No_])="SPD-25/06565" Or ([DDT_Picking Line].[Document No_])="SPD-25/06569" Or ([DDT_Picking Line].[Document No_])="SPD-25/07740" Or ([DDT_Picking Line].[Document No_])="SPD-25/07751" Or ([DDT_Picking Line].[Document No_])="SPD-25/07752" Or ([DDT_Picking Line].[Document No_])="SPD-25/07753" Or ([DDT_Picking Line].[Document No_])="SPD-25/06499" Or ([DDT_Picking Line].[Document No_])="SPD-25/06570" Or ([DDT_Picking Line].[Document No_])="SPD-25/06509" Or ([DDT_Picking Line].[Document No_])="SPD-25/06526") AND (([DDT_Picking Line].Type)=20));

